// do executes an HTTP request. headerOverrides, when non-nil, override global
// RequiredHeaders for this specific request (used for per-endpoint API versioning).
func (c *Client) do(method, path string, params map[string]string, body any, headerOverrides map[string]string) (json.RawMessage, int, error) {
	targetURL := c.BaseURL + path

	var bodyBytes []byte
	var contentType string
	if body != nil {
		if formBody, ok := body.(formRequestBody); ok {
			if path == "/api/graphql/" && !c.DryRun {
				fields := cloneFormValues(formBody.Fields)
				headers := cloneHeaders(headerOverrides)
				if err := c.addFacebookGraphQLSessionFields(fields, headers); err != nil {
					return nil, 0, err
				}
				if data, status, err := c.postFacebookGraphQLViaBrowserContext(fields, headers); err == nil {
					data = sanitizeJSONResponse(data)
					if status < 400 {
						return json.RawMessage(data), status, nil
					}
					return nil, status, &APIError{Method: "POST", Path: path, StatusCode: status, Body: truncateBody(data)}
				}
				formBody.Fields = fields
				headerOverrides = headers
			}
			b, ct, err := encodeFormBody(formBody)
			if err != nil {
				return nil, 0, err
			}
			bodyBytes = b
			contentType = ct
		} else {
			b, err := json.Marshal(body)
			if err != nil {
				return nil, 0, fmt.Errorf("marshaling body: %w", err)
			}
			bodyBytes = b
			contentType = "application/json"
		}
	}

	// Resolve auth material before the dry-run branch so --dry-run can preview
	// exactly what would be sent. Uses only cached credentials; a token that
	// requires a network refresh will be re-fetched on the live request path,
	// not during dry-run.
	authHeader, err := c.authHeader()
	if err != nil {
		return nil, 0, err
	}

	// Build the request for dry-run display or actual execution
	if c.DryRun {
		return c.dryRun(method, targetURL, path, params, bodyBytes, headerOverrides, authHeader)
	}

	const maxRetries = 3
	var lastErr error

	for attempt := 0; attempt <= maxRetries; attempt++ {
		// Proactive rate limiting — wait before sending
		c.limiter.Wait()
		var bodyReader io.Reader
		if bodyBytes != nil {
			bodyReader = strings.NewReader(string(bodyBytes))
		}

		req, err := http.NewRequest(method, targetURL, bodyReader)
		if err != nil {
			return nil, 0, fmt.Errorf("creating request: %w", err)
		}
		if bodyBytes != nil {
			req.Header.Set("Content-Type", contentType)
		}

		if params != nil {
			q := req.URL.Query()
			for k, v := range params {
				if v != "" {
					q.Set(k, v)
				}
			}
			req.URL.RawQuery = q.Encode()
		}

		if authHeader != "" {
			req.Header.Set("Cookie", authHeader)
		}
		if c.Config != nil {
			for k, v := range c.Config.Headers {
				req.Header.Set(k, v)
			}
		}
		// Per-endpoint header overrides (e.g., different API version per resource)
		for k, v := range headerOverrides {
			req.Header.Set(k, v)
		}

		resp, err := c.HTTPClient.Do(req)
		if err != nil {
			lastErr = fmt.Errorf("%s %s: %w", method, path, err)
			continue
		}

		respBody, err := io.ReadAll(resp.Body)
		resp.Body.Close()
		if err != nil {
			return nil, 0, fmt.Errorf("reading response: %w", err)
		}
		respBody = sanitizeJSONResponse(respBody)

		// Success
		if resp.StatusCode < 400 {
			c.limiter.OnSuccess()
			if method != http.MethodGet && !c.DryRun {
				c.invalidateCache()
			}
			return json.RawMessage(respBody), resp.StatusCode, nil
		}

		apiErr := &APIError{
			Method:     method,
			Path:       path,
			StatusCode: resp.StatusCode,
			Body:       truncateBody(respBody),
		}

		// Rate limited - adjust adaptive limiter and retry
		if resp.StatusCode == 429 && attempt < maxRetries {
			c.limiter.OnRateLimit()
			wait := cliutil.RetryAfter(resp)
			fmt.Fprintf(os.Stderr, "rate limited, waiting %s (attempt %d/%d, rate adjusted to %.1f req/s)\n", wait, attempt+1, maxRetries, c.limiter.Rate())
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Server error - retry with backoff
		if resp.StatusCode >= 500 && attempt < maxRetries {
			wait := time.Duration(math.Pow(2, float64(attempt))) * time.Second
			fmt.Fprintf(os.Stderr, "server error %d, retrying in %s (attempt %d/%d)\n", resp.StatusCode, wait, attempt+1, maxRetries)
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Client error or retries exhausted - return the error
		return nil, resp.StatusCode, apiErr
	}

	return nil, 0, lastErr
}

func cloneFormValues(values url.Values) url.Values {
	clone := make(url.Values, len(values))
	for key, vals := range values {
		clone[key] = append([]string(nil), vals...)
	}
	return clone
}

func cloneHeaders(headers map[string]string) map[string]string {
	clone := make(map[string]string, len(headers)+4)
	for key, value := range headers {
		clone[key] = value
	}
	return clone
}

func (c *Client) addFacebookGraphQLSessionFields(fields url.Values, headers map[string]string) error {
	authHeader, err := c.authHeader()
	if err != nil {
		return err
	}
	if authHeader == "" {
		return nil
	}

	shell, err := c.fetchMarketplaceShell(authHeader)
	if err != nil {
		return err
	}
	fbDTSG := firstRegexGroup(shell,
		`"DTSGInitialData",\[\],\{"token":"([^"]+)"`,
		`"DTSG[^"]*",\[\],\{[^}]*"token":"([^"]+)"`,
		`"fb_dtsg":"([^"]+)"`,
		`name="fb_dtsg" value="([^"]+)"`,
	)
	lsd := firstRegexGroup(shell,
		`"LSD",\[\],\{"token":"([^"]+)"`,
		`name="lsd" value="([^"]+)"`,
	)
	jazoest := firstRegexGroup(shell,
		`name="jazoest" value="([^"]+)"`,
		`"jazoest",\s*"([^"]+)"`,
	)
	if jazoest == "" && fbDTSG != "" {
		jazoest = deriveJazoest(fbDTSG)
	}
	rev := firstRegexGroup(shell, `"__spin_r":(\d+)`, `"client_revision":(\d+)`)
	userID := firstRegexGroup(authHeader, `(?:^|;\s*)c_user=([^;]+)`)
	if fbDTSG == "" {
		if tokens, err := c.extractFacebookPageContextTokens(authHeader); err == nil {
			if tokens.FBDTSG != "" {
				fbDTSG = tokens.FBDTSG
			}
			if tokens.LSD != "" {
				lsd = tokens.LSD
			}
			if tokens.Jazoest != "" {
				jazoest = tokens.Jazoest
			}
			if tokens.Revision != "" {
				rev = tokens.Revision
			}
		}
	}
	if os.Getenv("FACEBOOK_MARKET_DEBUG_GRAPHQL") == "1" {
		fmt.Fprintf(os.Stderr, "facebook graphQL session fields: fb_dtsg=%t lsd=%t jazoest=%t rev=%t user=%t\n", fbDTSG != "", lsd != "", jazoest != "", rev != "", userID != "")
	}
	if fbDTSG == "" {
		return fmt.Errorf("facebook GraphQL page-context token fb_dtsg not available; open Facebook Marketplace in Chrome and enable View > Developer > Allow JavaScript from Apple Events, then retry")
	}

	setIfMissing(fields, "fb_api_caller_class", "RelayModern")
	setIfMissing(fields, "server_timestamps", "true")
	setIfMissing(fields, "__a", "1")
	setIfMissing(fields, "__req", "1")
	setIfMissing(fields, "dpr", "2")
	setIfMissing(fields, "__ccg", "EXCELLENT")
	setIfMissing(fields, "__rev", rev)
	setIfMissing(fields, "fb_dtsg", fbDTSG)
	setIfMissing(fields, "jazoest", jazoest)
	setIfMissing(fields, "lsd", lsd)
	setIfMissing(fields, "av", userID)
	setIfMissing(fields, "__user", userID)

	headers["Origin"] = c.BaseURL
	headers["Referer"] = c.BaseURL + "/marketplace/"
	if friendly := fields.Get("fb_api_req_friendly_name"); friendly != "" {
		headers["X-FB-Friendly-Name"] = friendly
	}
	if lsd != "" {
		headers["X-FB-LSD"] = lsd
	}
	return nil
}

func (c *Client) fetchMarketplaceShell(authHeader string) (string, error) {
	req, err := http.NewRequest(http.MethodGet, c.BaseURL+"/marketplace/", nil)
	if err != nil {
		return "", err
	}
	req.Header.Set("Cookie", authHeader)
	req.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")
	if c.Config != nil {
		for k, v := range c.Config.Headers {
			req.Header.Set(k, v)
		}
	}
	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", err
	}
	if resp.StatusCode >= 400 {
		return "", &APIError{Method: http.MethodGet, Path: "/marketplace/", StatusCode: resp.StatusCode, Body: truncateBody(body)}
	}
	return string(body), nil
}

func firstRegexGroup(value string, patterns ...string) string {
	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		matches := re.FindStringSubmatch(value)
		if len(matches) > 1 {
			return unquoteJSONString(matches[1])
		}
	}
	return ""
}

func unquoteJSONString(value string) string {
	unquoted, err := strconv.Unquote(`"` + value + `"`)
	if err != nil {
		return value
	}
	return unquoted
}

func deriveJazoest(token string) string {
	sum := 0
	for _, r := range token {
		sum += int(r)
	}
	return "2" + strconv.Itoa(sum)
}

func setIfMissing(values url.Values, key, value string) {
	if value == "" || values.Get(key) != "" {
		return
	}
	values.Set(key, value)
}

// dryRun prints the outgoing request exactly as the live path would send it,
// using the auth material already resolved in `do()`. Never triggers a network
// call — the caller is responsible for passing cached auth material only.
func (c *Client) dryRun(method, targetURL, path string, params map[string]string, body []byte, headerOverrides map[string]string, authHeader string) (json.RawMessage, int, error) {
	fmt.Fprintf(os.Stderr, "%s %s\n", method, targetURL)
	queryPrinted := false
	if params != nil {
		keys := make([]string, 0, len(params))
		for k := range params {
			if params[k] != "" {
				keys = append(keys, k)
			}
		}
		sort.Strings(keys)
		for _, k := range keys {
			sep := "?"
			if queryPrinted {
				sep = "&"
			}
			fmt.Fprintf(os.Stderr, "  %s%s=%s\n", sep, k, params[k])
			queryPrinted = true
		}
	}
	_ = queryPrinted
	if body != nil {
		var pretty json.RawMessage
		if json.Unmarshal(body, &pretty) == nil {
			enc := json.NewEncoder(os.Stderr)
			enc.SetIndent("  ", "  ")
			fmt.Fprintf(os.Stderr, "  Body:\n")
			enc.Encode(pretty)
		}
	}
	if authHeader != "" {
		fmt.Fprintf(os.Stderr, "  %s: %s\n", "Cookie", maskToken(authHeader))
	}
	fmt.Fprintf(os.Stderr, "\n(dry run - no request sent)\n")
	return json.RawMessage(`{"dry_run": true}`), 0, nil
}

func (c *Client) ConfiguredTimeout() time.Duration {
	if c.HTTPClient != nil && c.HTTPClient.Timeout > 0 {
		return c.HTTPClient.Timeout
	}
	return 30 * time.Second
}

